const items = $input.all();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter PRs updated in last 7 days
const weekPRs = items.filter(item => {
  const updated = new Date(item.json.updated_at);
  return updated >= sevenDaysAgo;
});

if (weekPRs.length === 0) {
  return [{
    json: {
      no_prs: true,
      message: "No PRs this week",
      stats: {}
    }
  }];
}

// Compute stats
const totalPRs = weekPRs.length;
const totalAdditions = weekPRs.reduce((sum, p) => sum + (p.json.additions || 0), 0);
const totalDeletions = weekPRs.reduce((sum, p) => sum + (p.json.deletions || 0), 0);
const totalFiles = weekPRs.reduce((sum, p) => sum + (p.json.changed_files || 0), 0);

// Most active author
const authorCount = {};
weekPRs.forEach(p => {
  const author = p.json.user?.login || "unknown";
  authorCount[author] = (authorCount[author] || 0) + 1;
});
const topAuthor = Object.entries(authorCount).sort((a, b) => b[1] - a[1])[0][0];

// PR titles list
const prList = weekPRs.map(p => `- #${p.json.number}: ${p.json.title} by ${p.json.user?.login}`).join("\n");

return [{
  json: {
    no_prs: false,
    total_prs: totalPRs,
    total_additions: totalAdditions,
    total_deletions: totalDeletions,
    total_files_changed: totalFiles,
    top_author: topAuthor,
    pr_list: prList,
    week_start: sevenDaysAgo.toDateString(),
    week_end: now.toDateString()
  }
}];

const stats = $input.first().json;

const prompt = `You are a tech lead writing a weekly code health digest for your team.

Here are this week's stats:
- Total PRs: ${stats.total_prs}
- Lines added: ${stats.total_additions}
- Lines deleted: ${stats.total_deletions}
- Files changed: ${stats.total_files_changed}
- Most active contributor: ${stats.top_author}
- Week: ${stats.week_start} to ${stats.week_end}

PRs this week:
${stats.pr_list}

Write a concise, insightful digest in 3 short paragraphs. Be direct, no fluff. Max 150 words.`;

return [{
  json: {
    ...stats,
    request_body: JSON.stringify({
      model: "openai/gpt-oss-20b:free",
      max_tokens: 300,
      messages: [{ role: "user", content: prompt }]
    })
  }
}];
